  1248→        })
  1249→        .from(trains)
  1250→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)))
  1251→        .groupBy(trains.fitnessStatus);
  1252→
  1253→      const statusMap = new Map(fitnessCounts.map((fc) => [fc.status, fc.count]));
  1254→
  1255→      const result: FleetStatistics = {
  1256→        fleetId,
