  /**
   * Install a component on a train.
   * Creates an installation record and updates the component's current train.
   *
   * Business rules:
   * - Component must not already be installed on another train
   * - Train must exist and be active
   * - Component mileage tracking starts from current train mileage
   */
  async installComponent(request: InstallComponentRequest): Promise<ComponentInstallation> {
    return this.inTransaction('installComponent', async (tx, span) => {
      const { componentId, trainId, position, workOrderId } = request;

      span.setAttribute('component.id', componentId);
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      // Get component
      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      // Check if component is already installed
      if (component.currentTrainId) {
        throw new BusinessRuleError(
          `Component ${component.serialNumber} is already installed on a train. Remove it first.`,
          {
            rule: 'component_already_installed',
            context: { componentId, currentTrainId: component.currentTrainId },
          }
        );
      }

      // Get target train
      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      if (!train.active) {
        throw new BusinessRuleError('Cannot install component on inactive train', {
          rule: 'train_inactive',
          context: { trainId },
        });
      }

      const today = new Date().toISOString().split('T')[0];
      const trainMileage = train.currentMileageKm;
      const componentMileage = component.componentMileageKm;

      // Create installation record
      const installationData: NewComponentInstallation = {
        componentId,
        trainId,
        position,
        installedDate: today,
        installedTrainMileageKm: trainMileage,
        installedComponentMileageKm: componentMileage,
        workOrderId,
      };

      const [installation] = await tx
        .insert(componentInstallations)
        .values(installationData)
        .returning();

      // Update component with current train
      await tx
        .update(trainComponents)
        .set({
          currentTrainId: trainId,
          currentPosition: position,
          installedDate: today,
          installedMileageKm: trainMileage,
          status: 'IN_SERVICE',
          updatedAt: new Date(),
        })
        .where(eq(trainComponents.id, componentId));

      span.setAttribute('installation.id', installation.id);

      this.log.info(
        {
          componentId,
          serialNumber: component.serialNumber,
          trainId,
          trainNumber: train.trainNumber,
          position,
          trainMileageAtInstall: trainMileage,
          componentMileageAtInstall: componentMileage,
        },
        'Component installed on train'
      );

      this.recordEvent('component.installed', {
        'component.id': componentId,
        'component.serialNumber': component.serialNumber,
        [MmsAttributes.TRAIN_ID]: trainId,
        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
        'component.position': position ?? 'unspecified',
      }, span);

      return installation;
    });
  }

  /**
   * Remove a component from a train.
   * Closes the installation record and updates component mileage.
   *
   * Business rules:
   * - Component must be installed on a train
   * - Component mileage is updated based on train mileage during installation
   */
  async removeComponent(request: RemoveComponentRequest): Promise<ComponentInstallation> {
    return this.inTransaction('removeComponent', async (tx, span) => {
      const { componentId, reason, workOrderId } = request;

      span.setAttribute('component.id', componentId);
      span.setAttribute('removal.reason', reason);

      // Get component with current train
      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
        with: {
          currentTrain: true,
        },
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      if (!component.currentTrainId) {
        throw new BusinessRuleError(
          `Component ${component.serialNumber} is not installed on any train`,
          {
            rule: 'component_not_installed',
            context: { componentId },
          }
        );
      }

      const train = component.currentTrain;
      if (!train) {
        throw new NotFoundError(`Train not found for component`, {
          entityType: 'train',
          entityId: component.currentTrainId,
        });
      }

      // Find the active installation record
      const activeInstallation = await tx.query.componentInstallations.findFirst({
        where: and(
          eq(componentInstallations.componentId, componentId),
          eq(componentInstallations.trainId, component.currentTrainId),
          sql`${componentInstallations.removedDate} IS NULL`
        ),
        orderBy: desc(componentInstallations.installedDate),
      });

      if (!activeInstallation) {
        throw new BusinessRuleError(
          'No active installation record found for component',
          {
            rule: 'no_active_installation',
            context: { componentId, trainId: component.currentTrainId },
          }
        );
      }

      const today = new Date().toISOString().split('T')[0];
      const currentTrainMileage = train.currentMileageKm;

      // Calculate mileage accumulated during this installation
      const mileageDuringInstallation = currentTrainMileage - activeInstallation.installedTrainMileageKm;
      const newComponentMileage = activeInstallation.installedComponentMileageKm + mileageDuringInstallation;

      // Update installation record with removal data
      const [updatedInstallation] = await tx
        .update(componentInstallations)
        .set({
          removedDate: today,
          removedTrainMileageKm: currentTrainMileage,
          removedComponentMileageKm: newComponentMileage,
          removalReason: reason,
          workOrderId: workOrderId ?? activeInstallation.workOrderId,
        })
        .where(eq(componentInstallations.id, activeInstallation.id))
        .returning();

      // Update component - clear current train, update mileage
      await tx
        .update(trainComponents)
        .set({
          currentTrainId: null,
          currentPosition: null,
          installedDate: null,
          installedMileageKm: null,
          componentMileageKm: newComponentMileage,
          status: 'SPARE',
          updatedAt: new Date(),
        })
        .where(eq(trainComponents.id, componentId));

      span.setAttribute('mileage.during_installation', mileageDuringInstallation);
      span.setAttribute('mileage.new_total', newComponentMileage);

      this.log.info(
        {
          componentId,
          serialNumber: component.serialNumber,
          trainId: component.currentTrainId,
          trainNumber: train.trainNumber,
          reason,
          mileageDuringInstallation,
          newComponentMileage,
        },
        'Component removed from train'
      );

      this.recordEvent('component.removed', {
        'component.id': componentId,
        'component.serialNumber': component.serialNumber,
        [MmsAttributes.TRAIN_ID]: component.currentTrainId,
        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
        'removal.reason': reason,
        'mileage.accumulated': mileageDuringInstallation,
      }, span);

      return updatedInstallation;
    });
  }

  /**
   * Transfer a component from one train to another.
   * Combines remove and install in a single transaction.
   *
   * Business rules:
   * - Component must be installed on a train
   * - Component mileage is updated during transfer
   * - New train must exist and be active
   */
  async transferComponent(request: TransferComponentRequest): Promise<{
    removal: ComponentInstallation;
    installation: ComponentInstallation;
    mileageAccumulated: number;
  }> {
    return this.inTransaction('transferComponent', async (tx, span) => {
      const { componentId, newTrainId, newPosition, reason = 'SWAP', workOrderId } = request;

      span.setAttribute('component.id', componentId);
      span.setAttribute('train.new', newTrainId);

      // Get component with current train
      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
        with: {
          currentTrain: true,
        },
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      if (!component.currentTrainId) {
        throw new BusinessRuleError(
          `Component ${component.serialNumber} is not installed. Use installComponent instead.`,
          {
            rule: 'component_not_installed',
            context: { componentId },
          }
        );
      }

      const oldTrain = component.currentTrain;
      if (!oldTrain) {
        throw new NotFoundError(`Train not found for component`, {
          entityType: 'train',
          entityId: component.currentTrainId,
        });
      }

      // Get new train
      const newTrain = await tx.query.trains.findFirst({
        where: eq(trains.id, newTrainId),
      });

      if (!newTrain) {
        throw new TrainNotFoundError(newTrainId);
      }

      if (!newTrain.active) {
        throw new BusinessRuleError('Cannot transfer component to inactive train', {
          rule: 'train_inactive',
          context: { trainId: newTrainId },
        });
      }

      span.setAttribute('train.old', component.currentTrainId);
      span.setAttribute(MmsAttributes.TRAIN_NUMBER, `${oldTrain.trainNumber} -> ${newTrain.trainNumber}`);

      // Find active installation
      const activeInstallation = await tx.query.componentInstallations.findFirst({
        where: and(
          eq(componentInstallations.componentId, componentId),
          eq(componentInstallations.trainId, component.currentTrainId),
          sql`${componentInstallations.removedDate} IS NULL`
        ),
        orderBy: desc(componentInstallations.installedDate),
      });

      if (!activeInstallation) {
        throw new BusinessRuleError('No active installation record found', {
          rule: 'no_active_installation',
          context: { componentId },
        });
      }

      const today = new Date().toISOString().split('T')[0];
      const oldTrainMileage = oldTrain.currentMileageKm;
      const newTrainMileage = newTrain.currentMileageKm;

      // Calculate mileage accumulated during previous installation
      const mileageAccumulated = oldTrainMileage - activeInstallation.installedTrainMileageKm;
      const updatedComponentMileage = activeInstallation.installedComponentMileageKm + mileageAccumulated;

      // Close the old installation record
      const [removalRecord] = await tx
        .update(componentInstallations)
        .set({
          removedDate: today,
          removedTrainMileageKm: oldTrainMileage,
          removedComponentMileageKm: updatedComponentMileage,
          removalReason: reason,
          workOrderId,
        })
        .where(eq(componentInstallations.id, activeInstallation.id))
        .returning();

      // Create new installation record
      const newInstallationData: NewComponentInstallation = {
        componentId,
        trainId: newTrainId,
        position: newPosition,
        installedDate: today,
        installedTrainMileageKm: newTrainMileage,
        installedComponentMileageKm: updatedComponentMileage,
        workOrderId,
      };

      const [installationRecord] = await tx
        .insert(componentInstallations)
        .values(newInstallationData)
        .returning();

      // Update component
      await tx
        .update(trainComponents)
        .set({
          currentTrainId: newTrainId,
          currentPosition: newPosition,
          installedDate: today,
          installedMileageKm: newTrainMileage,
          componentMileageKm: updatedComponentMileage,
          status: 'IN_SERVICE',
          updatedAt: new Date(),
        })
        .where(eq(trainComponents.id, componentId));

      span.setAttribute('mileage.accumulated', mileageAccumulated);
      span.setAttribute('mileage.component_total', updatedComponentMileage);

      this.log.info(
        {
          componentId,
          serialNumber: component.serialNumber,
          oldTrainId: component.currentTrainId,
          oldTrainNumber: oldTrain.trainNumber,
          newTrainId,
          newTrainNumber: newTrain.trainNumber,
          position: newPosition,
          mileageAccumulated,
          newComponentMileage: updatedComponentMileage,
        },
        'Component transferred between trains'
      );

      this.recordEvent('component.transferred', {
        'component.id': componentId,
        'component.serialNumber': component.serialNumber,
        'train.old.id': component.currentTrainId,
        'train.old.number': oldTrain.trainNumber,
        'train.new.id': newTrainId,
        'train.new.number': newTrain.trainNumber,
        'mileage.accumulated': mileageAccumulated,
      }, span);

      return {
        removal: removalRecord,
        installation: installationRecord,
        mileageAccumulated,
      };
    });
  }

  /**
   * Recalculate and update component mileage based on installation history.
   * Useful for reconciliation or after data corrections.
   */
  async recalculateComponentMileage(componentId: string): Promise<ComponentMileageResult> {
    return this.inTransaction('recalculateComponentMileage', async (tx, span) => {
      span.setAttribute('component.id', componentId);

      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
        with: {
          installations: {
            orderBy: asc(componentInstallations.installedDate),
          },
          currentTrain: true,
        },
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      let totalMileage = 0;
      let installationsCalculated = 0;

      for (const installation of component.installations) {
        if (installation.removedDate && installation.removedTrainMileageKm !== null) {
          // Completed installation - use recorded values
          const mileageDelta = installation.removedTrainMileageKm - installation.installedTrainMileageKm;
          totalMileage += Math.max(0, mileageDelta);
          installationsCalculated++;
        } else if (component.currentTrain && component.currentTrainId === installation.trainId) {
          // Active installation - calculate from current train mileage
          const mileageDelta = component.currentTrain.currentMileageKm - installation.installedTrainMileageKm;
          totalMileage += Math.max(0, mileageDelta);
          installationsCalculated++;
        }
      }

      // Update component mileage
      await tx
        .update(trainComponents)
        .set({
          componentMileageKm: totalMileage,
          updatedAt: new Date(),
        })
        .where(eq(trainComponents.id, componentId));

      span.setAttribute('mileage.calculated', totalMileage);
      span.setAttribute('installations.count', installationsCalculated);

      this.log.info(
        {
          componentId,
          serialNumber: component.serialNumber,
          totalMileage,
          installationsCalculated,
        },
        'Component mileage recalculated'
      );

      return {
        componentId,
        serialNumber: component.serialNumber,
        totalComponentMileageKm: totalMileage,
        installationsCalculated,
      };
    });
  }

  /**
   * Get installation history for a component
   */
  async getComponentInstallationHistory(componentId: string): Promise<ComponentInstallation[]> {
    return this.traced('getComponentInstallationHistory', async (span) => {
      span.setAttribute('component.id', componentId);

      // Verify component exists
      const component = await this.db.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      const history = await this.db.query.componentInstallations.findMany({
        where: eq(componentInstallations.componentId, componentId),
        orderBy: desc(componentInstallations.installedDate),
      });

      span.setAttribute('result.count', history.length);
      return history;
    });
  }

  /**
   * Get all components currently installed on a train
   */
  async getTrainComponents(trainId: string): Promise<TrainComponent[]> {
    return this.traced('getTrainComponents', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      // Verify train exists
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const components = await this.db.query.trainComponents.findMany({
        where: eq(trainComponents.currentTrainId, trainId),
        orderBy: [asc(trainComponents.componentType), asc(trainComponents.currentPosition)],
      });

      span.setAttribute('result.count', components.length);
      return components;
    });
  }

  // ===========================================================================
  // Component PM Tracking
  // ===========================================================================

  /**
   * Get PM tracking status for a component
   */
  async getComponentPmStatus(componentId: string): Promise<ComponentPmTracking[]> {
    return this.traced('getComponentPmStatus', async (span) => {
      span.setAttribute('component.id', componentId);

      // Verify component exists
      const component = await this.db.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      const pmStatus = await this.db.query.componentPmTracking.findMany({
        where: eq(componentPmTracking.componentId, componentId),
      });

      span.setAttribute('result.count', pmStatus.length);
      return pmStatus;
    });
  }

  /**
   * Update or create PM tracking status for a component
   */
  async updateComponentPmStatus(
    componentId: string,
    pmTypeId: string,
    lastPmDate: string,
    lastPmMileageKm: number
  ): Promise<ComponentPmTracking> {
    return this.inTransaction('updateComponentPmStatus', async (tx, span) => {
      span.setAttribute('component.id', componentId);
      span.setAttribute('pmType.id', pmTypeId);

      // Verify component exists
      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      // Check if tracking record exists
      const existing = await tx.query.componentPmTracking.findFirst({
        where: and(
          eq(componentPmTracking.componentId, componentId),
          eq(componentPmTracking.pmTypeId, pmTypeId)
        ),
      });

      if (existing) {
        // Update existing record
        const [result] = await tx
          .update(componentPmTracking)
          .set({
            lastPmDate,
            lastPmMileageKm,
            updatedAt: new Date(),
          })
          .where(eq(componentPmTracking.id, existing.id))
          .returning();

        this.log.info(
          { componentId, pmTypeId, lastPmDate, lastPmMileageKm },
          'Component PM status updated'
        );
        return result;
      } else {
        // Create new record
        const [result] = await tx
          .insert(componentPmTracking)
          .values({
            componentId,
            pmTypeId,
            lastPmDate,
            lastPmMileageKm,
          })
          .returning();

        this.log.info(
          { componentId, pmTypeId, lastPmDate, lastPmMileageKm },
          'Component PM tracking created'
        );
        return result;
      }
    });
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let fleetServiceInstance: FleetService | null = null;

export function getFleetService(): FleetService {
  if (!fleetServiceInstance) {
    fleetServiceInstance = new FleetService();
  }
  return fleetServiceInstance;
}

export default FleetService;

